import base64
import zipfile
import io
import os

print("Building AllPro Refactored Website...")

zip_b64 = ""
zip_data = base64.b64decode(zip_b64)

with open("AllPro_Refactored.zip", "wb") as f:
    f.write(zip_data)

with zipfile.ZipFile(io.BytesIO(zip_data)) as zf:
    zf.extractall(".")

print("✅ Successfully built all files in the current directory!")
